  it("should reset focus to first match when query changes reduce matches", async () => {
    const scrollIntoViewMock = jest.fn();
    window.HTMLElement.prototype.scrollIntoView = scrollIntoViewMock;

    API.setElements([
      API.createElement({ type: "text", text: "alpha beta" }),
      API.createElement({ type: "text", text: "alpha gamma" }),
      API.createElement({ type: "text", text: "alpha delta" }),
      API.createElement({ type: "text", text: "beta only" }),
    ]);

    Keyboard.withModifierKeys({ ctrl: true }, () => {
      Keyboard.keyPress(KEYS.F);
    });

    const searchInput = await querySearchInput();
    updateTextEditor(searchInput, "alpha");

    await waitFor(() => {
      expect(h.app.state.searchMatches?.matches.length).toBe(3);
      expect(h.app.state.searchMatches?.matches[0].focus).toBe(true);
    });

    // navigate to the last match (index 2)
    Keyboard.keyPress(KEYS.ENTER, searchInput);
    Keyboard.keyPress(KEYS.ENTER, searchInput);
    expect(h.app.state.searchMatches?.matches[2].focus).toBe(true);

    // change query so only 1 match remains — old focusIndex (2) would be
    // out of bounds without the fix
    updateTextEditor(searchInput, "beta only");

    await waitFor(() => {
      expect(h.app.state.searchMatches?.matches.length).toBe(1);
      // focus must land on the first (and only) match, not beyond the array
      expect(h.app.state.searchMatches?.matches[0].focus).toBe(true);
    });
  });
});

